class Solution {
public:
    int minStable(vector<int>& nums, int maxC) {
        int n = nums.size();
        int ans = 0;
        for (int i = 0; i < n; i++) {
            int cnt = 0;
            for (int j = i; j < n; j++) {
                if (gcd(nums[i], nums[j]) >= 2) {
                    cnt++;
                } else {
                    break;
                }
                ans = max(ans, cnt);
            }
        }
        int mod = 0;
        for (int i = 0; i < n; i++) {
            if (nums[i] % 2 == 1) {
                mod++;
            }
        }
        return min(ans, max(0, n - mod - maxC));
    }
};
```

